arguments.argument:
JARS_DIR="${project.build.directory}/dependency-jars";
TEMPLATE="${project.basedir}/src/main/webapp/WEB-INF/weblogic.xml";
OUT_DIR="${project.build.directory}/generated-webapp/WEB-INF";
mkdir -p "$OUT_DIR";
PACKAGES=$(
  for jar in "$JARS_DIR"/*.jar; do
    jar tf "$jar" 2>/dev/null;
  done | grep '\.class$' | grep -v 'META-INF/' | grep -v 'module-info' |
  sed 's|/[^/]*\.class$||' | sed 's|/|.|g' |
  awk -F. '{
    if (NF >= 3) print $1"."$2"."$3
    else if (NF == 2) print $1"."$2
    else if (NF >= 1) print $1
  }' | sort -u
);
while IFS= read -r line; do
  if echo "$line" | grep -q 'AUTO-GENERATED'; then
    echo "$PACKAGES" | while read -r pkg; do
      if [ -n "$pkg" ]; then
        echo "            <wls:package-name>$pkg.*</wls:package-name>"
      fi
    done
  else
    echo "$line"
  fi
done < "$TEMPLATE" > "$OUT_DIR/weblogic.xml";
COUNT=$(echo "$PACKAGES" | grep -c . || true);
echo "Generated prefer-application-packages with $COUNT entries"

JAVA_VER="${java.version}";
if [ "$JAVA_VER" = "11" ]; then
  WARFILE="${project.build.directory}/${project.build.finalName}.war";
  TMPDIR="${project.build.directory}/war-strip-tmp";
  mkdir -p "$TMPDIR" && cd "$TMPDIR" &&
  jar xf "$WARFILE" WEB-INF/lib/;
  for jar in WEB-INF/lib/*.jar; do
    for ver in $(jar tf "$jar" 2>/dev/null | grep 'META-INF/versions/' | sed 's|META-INF/versions/||' | cut -d/ -f1 | sort -un); do
      if [ "$ver" -gt 11 ]; then
        zip -qd "$jar" "META-INF/versions/$ver/*" 2>/dev/null || true
      fi
    done
  done;
  jar uf "$WARFILE" WEB-INF/lib/;
  rm -rf "$TMPDIR";
  echo "Stripped multi-release classes above Java 11 from shared WAR JARs"
else
  echo "Skipping multi-release stripping (java.version=$JAVA_VER, only needed for 11)"
fi
